import (
	context "context"
	fern "github.com/inferred-auth-implicit-reference/fern"
	fernclient "github.com/inferred-auth-implicit-reference/fern/client"
	option "github.com/inferred-auth-implicit-reference/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Auth.Gettokenwithclientcredentials(
	context.TODO(),
	&fern.GetTokenRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
		Audience:     fern.GetTokenRequestAudienceHttpsApiExampleCom,
		GrantType:    fern.GetTokenRequestGrantTypeClientCredentials,
	},
)

import (
	context "context"
	fern "github.com/inferred-auth-implicit-reference/fern"
	fernclient "github.com/inferred-auth-implicit-reference/fern/client"
	option "github.com/inferred-auth-implicit-reference/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Auth.Refreshtoken(
	context.TODO(),
	&fern.RefreshTokenRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
		RefreshToken: "refresh_token",
		Audience:     fern.RefreshTokenRequestAudienceHttpsApiExampleCom,
		GrantType:    fern.RefreshTokenRequestGrantTypeRefreshToken,
	},
)
